<?php require __DIR__ . '/../includes/functions.php'; $rows=fetchAll('SELECT * FROM newsletter_subscribers ORDER BY created_at DESC'); ?><!doctype html><html lang="de"><head><meta charset="utf-8"><link rel="stylesheet" href="/assets/css/style.css"><title>Subscribers</title></head><body class="admin"><div class="container"><h1>Newsletter-Abonnenten</h1><table class="admin-table"><tr><th>E-Mail</th><th>Datum</th><th>Ticket</th><th>Status</th></tr><?php foreach($rows as $r):?><tr><td><?=e($r['email'])?></td><td><?=e($r['created_at'])?></td><td><a href="/ticket.php?token=<?=e($r['ticket_token'])?>">Ticket-Link</a></td><td><?= $r['ticket_sent_at'] ? 'sent' : 'pending' ?></td></tr><?php endforeach;?></table></div></body></html>
